; with ActiveAccounts as (select a.account_id, a.account_name, a.region_id from dbo.accounts a where a.is_active = 1), RegionTotals as (select aa.region_id, count(*) as account_count, r.region_name from ActiveAccounts aa inner join dbo.regions r on r.region_id = aa.region_id group by aa.region_id, r.region_name) select rt.region_name, rt.account_count from RegionTotals rt where rt.account_count > 10 order by rt.account_count desc
